# Tuples can be dict keys because they are hashable
grid = {}
grid[(0, 0)] = "origin"
grid[(1, 2)] = "point A"
grid[(3, 4)] = "point B"

print(grid[(0, 0)])
print(grid[(1, 2)])

# Lists CANNOT be dict keys
try:
    bad = {[1, 2]: "nope"}
except TypeError as e:
    print(f"Error: {e}")
